mapper.select:
SELECT cs.*
FROM chapter_summary cs
JOIN book_chapter summary_chapter ON cs.chapter_id = summary_chapter.id
JOIN book_chapter current_chapter ON current_chapter.id = #{chapterId}
WHERE cs.book_id = #{bookId}
  AND current_chapter.book_id = #{bookId}
  AND summary_chapter.sort_order <= current_chapter.sort_order
  AND cs.status = 'COMPLETED'
ORDER BY summary_chapter.sort_order DESC
LIMIT 1

mapper.update:
UPDATE chapter_summary cs
JOIN book_chapter bc ON cs.chapter_id = bc.id
SET cs.status = 'DIRTY',
    cs.updated_at = NOW()
WHERE cs.book_id = #{bookId}
  AND bc.book_id = #{bookId}
  AND bc.sort_order > #{sortOrder}
  AND cs.status = 'COMPLETED'
